#!/usr/bin/env python3
# scripts/check_docs_gate.py
# Fails with exit code 1 if any required doc is not approved.
import yaml, sys
from pathlib import Path

checklist_path = Path(sys.argv[1])
checklist = yaml.safe_load(checklist_path.read_text())

failures = []
for doc_type, meta in checklist['documentation'].items():
    if not meta.get('approved', False):
        required = meta.get('required', True)
        if required:
            failures.append(f"  [{doc_type}] status={meta.get('status')} — not approved by {meta.get('reviewer', 'unknown')}")

if failures:
    print(f"DOCS GATE FAILED for {checklist['service']} {checklist['version']}:")
    for f in failures:
        print(f)
    print("\nAll required docs must be approved before launch proceeds.")
    sys.exit(1)
else:
    print(f"DOCS GATE PASSED for {checklist['service']} {checklist['version']}")
    sys.exit(0)

# Support Briefing: {Feature Name} — {Launch Date}

## What is launching (30-second version)
{Plain-language description without jargon. What can users now do that they couldn't before?}

## Who is affected
- Affected plans/tiers: {list}
- Opt-in or automatic: {specify}
- Rollout: {immediate / gradual — what percentage sees it on day 1}

## Anticipated support questions

### "Why is my existing integration behaving differently?"
{Answer — reference the migration guide or changelog entry}

### "The new feature returns an error I haven't seen before"
{List new error codes and their meaning. Link to the error reference.}

### "How do I opt out / roll back?"
{Specific instructions, including any grace period}

## What to escalate vs. handle
| Symptom | Handle in support | Escalate to engineering |
|---------|-------------------|------------------------|
| User confusion about new behavior | Yes — link to docs | No |
| Unexpected error codes | Yes if documented | Yes if undocumented |
| Performance complaints (latency) | Yes — log the report | Yes if systemic (>3 reports) |
| Data integrity questions | No — escalate immediately | @platform-oncall |

## Escalation path
1. #support Slack for user-level questions
2. #incidents for systemic issues
3. PagerDuty: alert 'triage-api-support' for critical escalations
4. Direct: @{engineering-contact} for P0 only

## Links
- Full changelog: {link}
- Migration guide: {link}
- Internal runbook: {link}
- Known issues tracker: {link}

#!/usr/bin/env python3
# scripts/gen_oncall_brief.py
# Generates a concise on-call briefing from the launch YAML.
import yaml, sys
from pathlib import Path
from datetime import datetime, timezone

launch = yaml.safe_load(Path(sys.argv[1]).read_text())
now = datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%M UTC")

print(f"""
ON-CALL BRIEFING — {launch['service']} v{launch['version']}
Generated: {now}
Launch window: {launch['launch_date']} {launch.get('launch_time', 'TBD')} UTC
Monitoring window: {launch.get('monitoring_window_hours', 48)}h

WHAT CHANGED
{launch.get('description', '(see launch doc)')}

WATCH THESE METRICS
""")

for metric in launch.get('monitoring', {}).get('metrics', []):
    print(f"  {metric['name']}: alert at {metric.get('alert_threshold', 'TBD')} (baseline: {metric.get('baseline', 'N/A')})")

rollback = launch.get('rollback', {})
print(f"""
ROLLBACK PROCEDURE
  Trigger: {rollback.get('trigger', 'See launch doc')}
  Command: {rollback.get('command', 'See runbook')}
  ETA: {rollback.get('eta_minutes', 'unknown')} minutes
  Owner: {rollback.get('owner', 'launch owner')}

ESCALATION
  P1+ → #incidents + PagerDuty
  P0 → @{launch.get('oncall_handle', 'engineering-lead')}

RUNBOOK: {launch.get('runbook_url', '(fill in)')}
LAUNCH DOC: {launch.get('launch_doc_url', '(fill in)')}
""")
